// src/pages/Leave/LeavePage.js
import React, { useState, useEffect, useCallback } from 'react';
import {
  CalendarDays, Plus, Check, X, Clock, AlertCircle,
  Send, BarChart2, Calendar, Edit3, Users, Settings,
  RefreshCw, ArrowRightLeft, Shield, CheckSquare, Square
} from 'lucide-react';
import toast from 'react-hot-toast';
import { leaveAPI, notificationAPI, employeeAPI } from '../../api/services';
import { Modal, Badge, SkeletonCard, InlineSpinner } from '../../components/common';
import { useAuth } from '../../context/AuthContext';

// ─── SAFE ERROR EXTRACTOR ────────────────────────────────────────────────────
const getErrMsg = (err) => {
  const d = err.response?.data;
  if (d?.error?.message) return d.error.message;
  if (typeof d?.error === 'string') return d.error;
  if (typeof d?.message === 'string') return d.message;
  return err.message || 'An unexpected error occurred';
};

// ─── INLINE MODAL ────────────────────────────────────────────────────────────
const InlineModal = ({ title, onClose, children }) => (
  <div style={{ position: 'fixed', top:0, left:0, right:0, bottom:0, background:'rgba(0,0,0,0.5)', zIndex: 1000, display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
    <div className="card" style={{ width: '100%', maxWidth: 500, maxHeight: '90vh', overflowY: 'auto', background: '#fff', borderRadius: 8 }}>
      <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between', padding: '1rem', borderBottom: '1px solid #eee' }}>
         <div className="card-title" style={{ fontWeight: 600, fontSize: '1.1rem', margin: 0 }}>{title}</div>
         <button className="btn btn-ghost" style={{ padding: 4, background: 'none', border: 'none', cursor: 'pointer' }} onClick={onClose}><X size={18}/></button>
      </div>
      <div style={{ padding: '1rem' }}>
        {children}
      </div>
    </div>
  </div>
);

// ─── STATUS CONSTANTS & HELPERS ──────────────────────────────────────────────
const STATUS_LABEL = {
  SUBMITTED: 'Submitted', PENDING_MANAGER: 'Pending Approval',
  PendingManager: 'Pending Approval', PENDING_HR: 'Pending HR',
  APPROVED: 'Approved', REJECTED: 'Rejected', CANCELLED: 'Cancelled',
  DRAFT: 'Draft', Submitted: 'Submitted', Pending: 'Pending Approval',
  Approved: 'Approved', Rejected: 'Rejected', Cancelled: 'Cancelled',
};

const normStatus = s => (s || '').toUpperCase().replace(/_/g, '');
const statusMatches = (reqStatus, filterValue) => {
  if (!filterValue) return true;
  const rs = normStatus(reqStatus);
  const fv = normStatus(filterValue);
  if (rs === fv) return true;
  const allPending = new Set(['PENDINGMANAGER','PENDINGHR','SUBMITTED','PENDING','DRAFT']);
  if (fv === 'PENDINGMANAGER' && allPending.has(rs)) return true;
  return false;
};
const isFinalStatus = s => ['APPROVED','REJECTED','CANCELLED'].includes(normStatus(s));

const toArr = (r) => {
  if (!r) return [];
  const d = r.data?.data || r.data?.requests || r.data || r.requests || r || [];
  return Array.isArray(d) ? d : [];
};

function RequestRow({ req, onAction, onEdit, onOverrideClick, isSupervisor, isHRManager, isBasicHR, currentUser, isSelected, onSelect }) {
  const [acting, setActing] = useState('');

  const leaveTypeName = req.LeaveType?.LeaveTypeName || req.leaveType?.LeaveTypeName || req.LeaveTypeName || req.leaveTypeName || '—';
  const empFullName = req.Employee?.FullName || req.employee?.fullName || req.EmployeeName || req.employeeName || '—';
  const startDate = req.StartDate || req.startDate;
  const endDate = req.EndDate || req.endDate;
  const totalDays = req.TotalDays ?? req.totalDays ?? '—';
  const currentStatus = req.Status || req.status || 'SUBMITTED';
  const leaveReason = req.Reason || req.reason || '—';
  const id = req.LeaveRequestID || req.id;

  const from = startDate ? new Date(startDate).toLocaleDateString() : '—';
  const to = endDate ? new Date(endDate).toLocaleDateString() : '—';

  const act = async (action) => {
    setActing(action);
    try { await onAction(id, action); } finally { setActing(''); }
  };

  const isFinal = isFinalStatus(currentStatus);
  const currentUserId = currentUser?.id || currentUser?.EmployeeID || currentUser?.employeeId;
  const empPosId = parseInt(req.Employee?.PositionID || req.employee?.PositionID || 0, 10);
  const empSupId = req.Employee?.SupervisorID || req.employee?.SupervisorID;

  const isHREmployee = [1, 10, 21].includes(empPosId);
  const isDirectReport = empSupId === currentUserId;

  // HR Manager Logic: Approve/Reject only for HR staff or direct reports. 
  // Otherwise, read-only until Override is possible.
  const canApproveReject = !isFinal && (
    (isSupervisor && !isHRManager) || 
    (isHRManager && (isHREmployee || isDirectReport))
  );

  const canOverride = isHRManager && isFinal && normStatus(currentStatus) !== 'CANCELLED';

  return (
    <tr style={{ background: isSelected ? 'rgba(59, 130, 246, 0.05)' : 'inherit' }}>
      {isHRManager && onSelect && (
        <td>
          <button className="btn btn-ghost p-1" onClick={() => onSelect(id)}>
            {isSelected ? <CheckSquare size={16} color="var(--blue)" /> : <Square size={16} color="#ccc" />}
          </button>
        </td>
      )}
      <td>
        <div style={{ fontWeight: 500 }}>{leaveTypeName}</div>
        {!(isSupervisor || isHRManager || isBasicHR) && leaveReason !== '—' && <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', marginTop: 2 }}>{leaveReason}</div>}
      </td>
      {(isSupervisor || isHRManager || isBasicHR) && <td><div style={{ fontWeight: 500 }}>{empFullName}</div></td>}
      <td style={{ fontSize: '0.82rem' }}>{from} → {to}</td>
      <td>{totalDays}</td>
      <td>
        <span style={{
          display: 'inline-block', padding: '3px 10px', borderRadius: 20, fontSize: '0.75rem', fontWeight: 600,
          background: normStatus(currentStatus) === 'APPROVED' ? 'rgba(34,197,94,0.15)' : normStatus(currentStatus) === 'REJECTED' ? 'rgba(239,68,68,0.15)' : 'rgba(251,191,36,0.15)',
          color: normStatus(currentStatus) === 'APPROVED' ? '#16a34a' : normStatus(currentStatus) === 'REJECTED' ? '#dc2626' : '#b45309',
        }}>{STATUS_LABEL[currentStatus] || currentStatus}</span>
      </td>
      {(isSupervisor || isHRManager || isBasicHR) && (
        <td style={{ fontSize: '0.78rem', color: 'var(--text-secondary)', maxWidth: 160 }}>
          {leaveReason.slice(0, 60)}{leaveReason.length > 60 ? '…' : ''}
        </td>
      )}
      <td>
        <div style={{ display: 'flex', gap: 6 }}>
          {canApproveReject && (
            <>
              <button className="btn btn-success btn-sm" onClick={() => act('approve')} disabled={!!acting}>{acting === 'approve' ? <InlineSpinner /> : 'Approve'}</button>
              <button className="btn btn-danger btn-sm" onClick={() => act('reject')} disabled={!!acting}>{acting === 'reject' ? <InlineSpinner /> : 'Reject'}</button>
            </>
          )}
          {canOverride && onOverrideClick && (
            <button className="btn btn-ghost btn-sm" onClick={() => onOverrideClick(req)} disabled={!!acting}><Shield size={13}/> Override</button>
          )}
          {!(isSupervisor || isHRManager || isBasicHR) && !isFinal && (
            <>
              {onEdit && <button className="btn btn-ghost btn-sm" onClick={() => onEdit(req)} disabled={!!acting}><Edit3 size={13} style={{marginRight: 4}}/> Edit</button>}
              <button className="btn btn-ghost btn-sm" onClick={() => act('cancel')} disabled={!!acting}>Cancel</button>
            </>
          )}
        </div>
      </td>
    </tr>
  );
}

// ─── UI COMPONENTS ───────────────────────────────────────────────────────────
function BalanceCard({ balance, loading }) {
  if (loading) return <SkeletonCard />;
  const name = balance.leaveTypeName || balance.LeaveTypeName || balance.LeaveType?.LeaveTypeName || 'Leave';
  const used = Number(balance.usedDays ?? balance.UsedDays ?? 0);
  const entitled = Number(balance.entitledDays ?? balance.EntitledDays ?? 0);
  const carryOver = Number(balance.carryOverDays ?? balance.CarryOverDays ?? 0);
  const adjusted = Number(balance.adjustedDays ?? balance.AdjustedDays ?? 0);
  const remaining = Math.max(0, entitled + carryOver + adjusted - used);
  const maxDays = entitled + carryOver + adjusted;
  const pct = maxDays > 0 ? Math.round((remaining / maxDays) * 100) : 0;
  const color = name.includes('Sick') || name.includes('Medical') ? 'var(--green)' : 
                name.includes('Emergency') ? 'var(--red)' : 'var(--blue)';

  return (
    <div className="stat-card">
      <div className="stat-card-accent" style={{ background: color }} />
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 12 }}>
        <div style={{ fontSize: '0.78rem', color: 'var(--text-secondary)', fontWeight: 500, textTransform: 'uppercase' }}>{name}</div>
        <CalendarDays size={18} style={{ color }} />
      </div>
      <div className="stat-card-value" style={{ color }}>{remaining}</div>
      <div className="stat-card-label">days remaining of {maxDays}</div>
      <div className="stat-card-progress" style={{ marginTop: 12 }}><div className="stat-card-progress-bar" style={{ width: `${pct}%`, background: color }} /></div>
      <div className="stat-card-meta"><span>{used} used (Approved)</span><span>{pct}%</span></div>
    </div>
  );
}

// ─── MODALS & FORMS ──────────────────────────────────────────────────────────
function SubmitLeaveForm({ leaveTypes, onSubmit, loading }) {
  const [form, setForm] = useState({ LeaveTypeID: '', startDate: '', endDate: '', reason: '', isHalfDay: false, documentReference: null });

  const handle = () => {
    if (!form.LeaveTypeID || !form.startDate || !form.endDate) return toast.error("Please fill all required fields");
    const data = new FormData();
    data.append('LeaveTypeID', form.LeaveTypeID);
    data.append('StartDate', new Date(form.startDate).toISOString());
    data.append('EndDate', new Date(form.endDate).toISOString());
    data.append('IsHalfDay', form.isHalfDay);
    data.append('Reason', form.reason || '');
    if (form.documentReference) data.append('documentReference', form.documentReference);
    onSubmit(data); 
  };

  return (
    <>
      <div className="form-group"><label className="form-label required">Leave Type</label>
        <select className="form-select" value={form.LeaveTypeID} onChange={e => setForm({...form, LeaveTypeID: e.target.value})}>
          <option value="">— Select a leave type —</option>
          {leaveTypes.map(t => <option key={t.LeaveTypeID || t.id} value={t.LeaveTypeID || t.id}>{t.LeaveTypeName || t.name}</option>)}
        </select>
      </div>
      <div className="form-row">
        <div className="form-group"><label className="form-label required">Start Date</label><input className="form-input" type="date" value={form.startDate} onChange={e => setForm({...form, startDate: e.target.value})} /></div>
        <div className="form-group"><label className="form-label required">End Date</label><input className="form-input" type="date" value={form.endDate} min={form.startDate} onChange={e => setForm({...form, endDate: e.target.value})} /></div>
      </div>
      <div className="form-group"><label style={{display:'flex',alignItems:'center',gap:8,cursor:'pointer',fontSize:'0.875rem'}}><input type="checkbox" checked={form.isHalfDay} onChange={e => setForm({...form, isHalfDay: e.target.checked})} /><span>Half-day</span></label></div>
      <div className="form-group"><label className="form-label">Reason</label><textarea className="form-textarea" rows={2} value={form.reason} onChange={e => setForm({...form, reason: e.target.value})} /></div>
      <div className="form-group">
        <label className="form-label">Medical Document (PDF/Image)</label>
        <input className="form-input" type="file" accept="image/*,application/pdf" onChange={e => setForm({...form, documentReference: e.target.files[0]})} />
      </div>
      <div style={{ display: 'flex', justifyContent: 'flex-end', marginTop: 16 }}>
        <button className="btn btn-primary" onClick={handle} disabled={loading}>{loading ? <InlineSpinner /> : 'Submit Request'}</button>
      </div>
    </>
  );
}

function EditLeaveForm({ req, onSubmit, loading }) {
  const [form, setForm] = useState({ 
    startDate: req.StartDate ? req.StartDate.split('T')[0] : '', 
    endDate: req.EndDate ? req.EndDate.split('T')[0] : '', 
    reason: req.Reason || '' 
  });

  const handle = () => {
    if (!form.startDate || !form.endDate) return toast.error("Required fields missing");
    onSubmit(req.LeaveRequestID || req.id, {
      StartDate: new Date(form.startDate).toISOString(),
      EndDate: new Date(form.endDate).toISOString(),
      Reason: form.reason || null
    });
  };

  return (
    <>
      <div className="form-row">
        <div className="form-group"><label className="form-label required">Start Date</label><input className="form-input" type="date" value={form.startDate} onChange={e => setForm({...form, startDate: e.target.value})} /></div>
        <div className="form-group"><label className="form-label required">End Date</label><input className="form-input" type="date" value={form.endDate} min={form.startDate} onChange={e => setForm({...form, endDate: e.target.value})} /></div>
      </div>
      <div className="form-group"><label className="form-label">Reason</label><textarea className="form-textarea" rows={3} value={form.reason} onChange={e => setForm({...form, reason: e.target.value})} /></div>
      <div style={{ display: 'flex', justifyContent: 'flex-end', marginTop: 16 }}><button className="btn btn-primary" onClick={handle} disabled={loading}>{loading ? <InlineSpinner /> : 'Update Request'}</button></div>
    </>
  );
}

function ManualAdjustmentModal({ employees, leaveTypes, onConfirm, onClose, loading }) {
  const [form, setForm] = useState({ EmployeeID: '', LeaveTypeID: '', AdjustedDays: '', Reason: '' });
  return (
    <InlineModal title="Manual Balance Adjustment" onClose={onClose}>
      <div className="form-group"><label className="form-label">Employee</label>
        <select className="form-select" onChange={e => setForm({...form, EmployeeID: e.target.value})}>
          <option value="">Select Employee</option>
          {employees.map(emp => <option key={emp.id} value={emp.id}>{emp.name}</option>)}
        </select>
      </div>
      <div className="form-group"><label className="form-label">Leave Type</label>
        <select className="form-select" onChange={e => setForm({...form, LeaveTypeID: e.target.value})}>
          <option value="">Select Type</option>
          {leaveTypes.map(t => <option key={t.LeaveTypeID || t.id} value={t.LeaveTypeID || t.id}>{t.LeaveTypeName || t.name}</option>)}
        </select>
      </div>
      <div className="form-group"><label className="form-label">Adjustment (+/- Days)</label><input className="form-input" type="number" onChange={e => setForm({...form, AdjustedDays: e.target.value})} placeholder="e.g. 5 or -2" /></div>
      <div className="form-group"><label className="form-label">Reason</label><textarea className="form-textarea" rows={2} onChange={e => setForm({...form, Reason: e.target.value})} placeholder="Justification..." /></div>
      <div className="d-flex gap-2 mt-4 justify-content-end"><button className="btn btn-ghost" onClick={onClose}>Cancel</button><button className="btn btn-primary" disabled={loading} onClick={() => onConfirm(form)}>{loading ? <InlineSpinner /> : 'Update Balance'}</button></div>
    </InlineModal>
  );
}

function RolePermissionManager({ employees, onUpdate }) {
  const [form, setForm] = useState({ employeeId: '', positionId: '' });
  return (
    <div className="card p-4">
      <div className="card-title"><Shield size={16} style={{marginRight: 6}}/> Roles & Permissions</div>
      <div className="form-row mt-3">
        <div className="form-group" style={{ flex: 1 }}><label className="form-label">Employee</label><select className="form-select" value={form.employeeId} onChange={e => setForm({...form, employeeId: e.target.value})}><option value="">Select Employee...</option>{employees.map(emp => <option key={emp.id} value={emp.id}>{emp.name}</option>)}</select></div>
        <div className="form-group" style={{ flex: 1 }}><label className="form-label">System Role</label><select className="form-select" value={form.positionId} onChange={e => setForm({...form, positionId: e.target.value})}><option value="">Select Role...</option><option value="1">HR Manager</option><option value="10">HR Specialist</option><option value="2">Manager</option><option value="0">Employee</option></select></div>
      </div>
      <button className="btn btn-primary btn-sm mt-2" disabled={!form.employeeId || !form.positionId} onClick={() => { onUpdate(form); setForm({employeeId: '', positionId: ''}); }}>Update Role</button>
    </div>
  );
}

function LeavePolicyManager({ leaveTypes, onSave }) {
  const [policy, setPolicy] = useState({ LeaveTypeID: '', MinTenureMonths: 0, NoticePeriodDays: 0 });
  return (
    <div className="card p-4">
      <div className="card-title"><CalendarDays size={16} style={{marginRight: 6}}/> Leave Policy Engine</div>
      <div className="form-row mt-3">
        <div className="form-group" style={{ flex: 1 }}><label className="form-label">Leave Type</label><select className="form-select" value={policy.LeaveTypeID} onChange={e => setPolicy({...policy, LeaveTypeID: e.target.value})}><option value="">Select Type...</option>{leaveTypes.map(t => <option key={t.LeaveTypeID || t.id} value={t.LeaveTypeID || t.id}>{t.LeaveTypeName || t.name}</option>)}</select></div>
        <div className="form-group" style={{ flex: 1 }}><label className="form-label">Min Tenure (Months)</label><input className="form-input" type="number" value={policy.MinTenureMonths} onChange={e => setPolicy({...policy, MinTenureMonths: e.target.value})} /></div>
        <div className="form-group" style={{ flex: 1 }}><label className="form-label">Required Notice (Days)</label><input className="form-input" type="number" value={policy.NoticePeriodDays} onChange={e => setPolicy({...policy, NoticePeriodDays: e.target.value})} /></div>
      </div>
      <button className="btn btn-primary btn-sm mt-2" disabled={!policy.LeaveTypeID} onClick={() => onSave(policy)}>Save Policy Rules</button>
    </div>
  );
}

// ─── MAIN COMPONENT ──────────────────────────────────────────────────────────
export default function LeavePage() {
  const { user } = useAuth();

  const posId = parseInt(user?.PositionID || user?.positionId || 0, 10);
  const rawRole = String(user?.role || user?.Role || '').toUpperCase();
  const rawTitle = String(user?.position || user?.Position?.PositionTitle || '').toUpperCase();

  const isHRManager = posId === 1 || rawTitle === 'HR MANAGER';
  const isBasicHR = !isHRManager && (posId === 10 || posId === 21 || rawRole === 'HR' || rawTitle === 'HR SPECIALIST' || rawTitle === 'HR-GEN');
  const isSupervisor = !isHRManager && !isBasicHR && (
    posId === 2 || posId === 8 || posId === 9 || rawRole === 'MANAGER' || rawTitle.includes('MANAGER')
  );

  const isManagement = isHRManager || isSupervisor;

  const [tab, setTab] = useState('dashboard');
  const [balances, setBalances] = useState([]);
  const [myRequests, setMyReqs] = useState([]);
  const [allRequests, setAll] = useState([]);
  const [leaveTypes, setTypes] = useState([]);
  const [holidays, setHolidays] = useState([]);
  const [allEmployees, setAllEmployees] = useState([]);
  const [selectedIds, setSelectedIds] = useState([]); 

  const [loadBal, setLoadBal] = useState(true);
  const [loadReq, setLoadReq] = useState(true);
  const [loadAll, setLoadAll] = useState(true);
  const [isSubmitModalOpen, setIsSubmitModalOpen] = useState(false);
  const [showAdjustmentModal, setShowAdjustmentModal] = useState(false);
  const [editReq, setEditReq] = useState(null);
  const [overrideReq, setOverrideReq] = useState(null); 

  const loadData = useCallback(() => {
    setLoadBal(true); setLoadReq(true);
    leaveAPI.getMyBalances().then(r => setBalances(toArr(r))).finally(() => setLoadBal(false));
    leaveAPI.getMyRequests().then(r => setMyReqs(toArr(r))).finally(() => setLoadReq(false));
    if (leaveAPI.getTypes) leaveAPI.getTypes().then(r => setTypes(toArr(r)));
    if ((isHRManager || isBasicHR) && leaveAPI.listHolidays) leaveAPI.listHolidays().then(r => setHolidays(toArr(r)));
    if ((isHRManager || isBasicHR) && employeeAPI?.list) {
      employeeAPI.list({ limit: 500 }).then(r => {
        const emps = toArr(r).map(e => ({ id: e.EmployeeID || e.id, name: e.FullName || e.fullName }));
        setAllEmployees(emps);
      });
    }

    if (isManagement) {
      setLoadAll(true);
      const fetchMethod = isHRManager ? leaveAPI.listAll({ managerId: '' }) : leaveAPI.getManagerInbox();
      fetchMethod.then(r => setAll(toArr(r))).catch(() => setAll([])).finally(() => setLoadAll(false));
    }
  }, [isHRManager, isSupervisor, isBasicHR, isManagement]);

  useEffect(() => { loadData(); }, [loadData]);

  const handleAction = async (id, action) => {
    try {
      if (action === 'approve') await leaveAPI.approveReject(id, { decision: 'APPROVED' });
      else if (action === 'reject') await leaveAPI.approveReject(id, { decision: 'REJECTED', comments: 'Actioned by HR' });
      else if (action === 'cancel') await leaveAPI.cancel(id, { CancelReason: 'User Cancelled' });
      toast.success('Action successfully completed');
      loadData();
    } catch (err) { toast.error(getErrMsg(err)); }
  };

  const handleBulkAction = async (decision) => {
    if (!selectedIds.length) return;
    try {
      setLoadAll(true);
      await Promise.all(selectedIds.map(id => 
        leaveAPI.approveReject(id, { decision, comments: 'Bulk Processed by HR' })
      ));
      toast.success(`Successfully processed ${selectedIds.length} requests`);
      setSelectedIds([]);
      loadData();
    } catch (err) {
      toast.error("Error during bulk processing");
    } finally {
      setLoadAll(false);
    }
  };

  const toggleSelect = (id) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
  };

  const TABS = [
    { id: 'dashboard', label: 'Dashboard', icon: BarChart2 },
    { id: 'history', label: 'My History', icon: Clock },
    ...(isManagement ? [ { id: 'all', label: isHRManager ? 'Company Data' : 'Team Inbox', icon: Users } ] : []),
    ...(isHRManager || isBasicHR ? [ { id: 'settings', label: 'Settings', icon: Settings } ] : []),
  ];

  return (
    <>
      {overrideReq && isHRManager && (
        <InlineModal title="HR Security Override" onClose={() => setOverrideReq(null)}>
          <p>Manual override for <strong>{overrideReq.Employee?.FullName}</strong>.</p>
          <div style={{ display: 'flex', gap: '10px', marginTop: '20px' }}>
            <button className="btn btn-success" onClick={() => { handleAction(overrideReq.LeaveRequestID || overrideReq.id, 'approve'); setOverrideReq(null); }}>Force Approve</button>
            <button className="btn btn-danger" onClick={() => { handleAction(overrideReq.LeaveRequestID || overrideReq.id, 'reject'); setOverrideReq(null); }}>Force Reject</button>
          </div>
        </InlineModal>
      )}

      {editReq && (
        <InlineModal title="Edit Leave Request" onClose={() => setEditReq(null)}>
           <EditLeaveForm req={editReq} onSubmit={(id, data) => leaveAPI.updateRequest(id, data).then(() => { toast.success("Updated"); setEditReq(null); loadData(); })} loading={false} />
        </InlineModal>
      )}

      {showAdjustmentModal && isHRManager && (
        <ManualAdjustmentModal employees={allEmployees} leaveTypes={leaveTypes} onClose={() => setShowAdjustmentModal(false)} onConfirm={(d) => leaveAPI.adjustBalance(d).then(() => { toast.success("Adjusted"); setShowAdjustmentModal(false); loadData(); })} />
      )}

      {isSubmitModalOpen && (
        <InlineModal title="Submit Leave Request" onClose={() => setIsSubmitModalOpen(false)}>
           <SubmitLeaveForm leaveTypes={leaveTypes} onSubmit={(p) => leaveAPI.submit(p).then(() => { toast.success("Submitted"); setIsSubmitModalOpen(false); loadData(); })} loading={false} />
        </InlineModal>
      )}

      <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', padding: '1rem' }}>
        <div><h1>Leave Management</h1><p>Control requests, balances, and system rules</p></div>
        <button className="btn btn-primary" onClick={() => setIsSubmitModalOpen(true)}><Plus size={18} style={{ marginRight: 8 }} /> New Request</button>
      </div>

      <div className="tabs" style={{ padding: '0 1rem' }}>
        {TABS.map(({ id, label, icon: Icon }) => (
          <button key={id} className={`tab-btn ${tab === id ? 'active' : ''}`} onClick={() => setTab(id)}><Icon size={14} style={{ marginRight: 6 }} />{label}</button>
        ))}
      </div>

      <div style={{ padding: '1rem' }}>
        {tab === 'dashboard' && (
          <div className="grid-4" style={{ marginBottom: 28 }}>
            {loadBal ? <SkeletonCard /> : balances.map((b, i) => <BalanceCard key={i} balance={b} loading={false} />)}
          </div>
        )}

        {tab === 'history' && (
          <div className="card">
            <div className="table-wrap">
              <table>
                <thead><tr><th>Type</th><th>Period</th><th>Days</th><th>Status</th><th>Actions</th></tr></thead>
                <tbody>{myRequests.map((req, i) => <RequestRow key={i} req={req} onAction={handleAction} onEdit={setEditReq} currentUser={user} />)}</tbody>
              </table>
            </div>
          </div>
        )}

        {tab === 'all' && isManagement && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
            {isHRManager && selectedIds.length > 0 && (
              <div className="bulk-action-bar" style={{ padding: '1rem', background: '#3b82f6', color: 'white', borderRadius: 8, display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 12 }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                  <CheckSquare size={20} />
                  <span style={{ fontWeight: 600 }}>{selectedIds.length} requests selected for bulk processing</span>
                </div>
                <div style={{ display: 'flex', gap: 8 }}>
                   <button className="btn btn-success btn-sm" onClick={() => handleBulkAction('APPROVE')}>Bulk Approve</button>
                   <button className="btn btn-danger btn-sm" onClick={() => handleBulkAction('REJECT')}>Bulk Reject</button>
                   <button className="btn btn-ghost btn-sm" style={{ color: 'white', border: '1px solid white' }} onClick={() => setSelectedIds([])}>Cancel</button>
                </div>
              </div>
            )}
            <div className="card">
              <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between' }}>
                <div className="card-title">{isHRManager ? 'Company-Wide Leaves' : 'Team Pending Approvals'}</div>
                <button className="btn btn-ghost btn-sm" onClick={loadData}><RefreshCw size={14}/></button>
              </div>
              <div className="table-wrap">
                <table>
                  <thead>
                    <tr>
                      {isHRManager && <th style={{ width: 40 }}></th>}
                      <th>Type</th><th>Employee</th><th>Period</th><th>Days</th><th>Status</th><th>Reason</th><th>Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {allRequests.map((req, i) => (
                      <RequestRow 
                        key={i} 
                        req={req} 
                        onAction={handleAction} 
                        onOverrideClick={setOverrideReq} 
                        isSupervisor={isSupervisor} 
                        isHRManager={isHRManager} 
                        isBasicHR={isBasicHR} 
                        currentUser={user} 
                        isSelected={selectedIds.includes(req.LeaveRequestID || req.id)} 
                        onSelect={toggleSelect} 
                      />
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}

        {tab === 'settings' && (isHRManager || isBasicHR) && (
          <div className="settings-grid">
            <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
              <LeaveTypeManager types={leaveTypes} onAdd={d => leaveAPI.createType(d).then(() => { toast.success("Created"); loadData(); })} />
              <LeavePolicyManager leaveTypes={leaveTypes} onSave={d => leaveAPI.createPolicy(d).then(() => toast.success("Policy Saved"))} />
              <RolePermissionManager employees={allEmployees} onUpdate={d => employeeAPI.updateRole(d).then(() => toast.success("Role Updated"))} />
            </div>
            {isHRManager && (
              <div className="card p-4" style={{ height: 'fit-content' }}>
                <div className="card-title" style={{ marginBottom: 16 }}>Advanced HR Actions</div>
                <button className="btn btn-outline-danger w-full" onClick={() => setShowAdjustmentModal(true)}>
                  <Shield size={14} style={{ marginRight: 8 }} /> Manual Balance Adjustment
                </button>
                <p className="text-muted small mt-3">Manual adjustments will bypass standard entitlement rules and used day calculations.</p>
              </div>
            )}
          </div>
        )}
      </div>
    </>
  );
}
